mapper.select:
select id, file_type, test_time, file_title, content, create_time, update_time as publishDate, update_by, test_product_ids, test_merchant_ids, relation_file_ids, agency_name, remarks from cm_test_info where deleted = '0'
and file_title like concat('%', #{vo.fileTitle}, '%')
and create_time >= #{vo.startTime}
and create_time < #{vo.endTime}
order by update_time desc
